                Pair(data, count)
            }
            else -> {
                log.debug("Unsupported SQL exception status '{}' for non-admin, falling back", exceptionStatus)
                return getCurrentVulnerabilitiesOptimized(
                    accessibleAssetIds, false, severity, system, null, product,
