162→    setAssetSearchTerm('');
163→    setShowAssignAssets(true);
164→  };
165→
166→  /**
167→   * Filter assets based on search term with wildcard support
168→   * Supports: partial match, * wildcard, case-insensitive
169→   */
170→  const filterAssets = (searchTerm: string): Asset[] => {
171→    if (!searchTerm.trim()) {
172→      return assets;
173→    }
174→
175→    const term = searchTerm.toLowerCase().trim();
176→
177→    // Convert wildcard pattern to regex
178→    // * matches any characters, ? matches single character
179→    const regexPattern = term
180→      .replace(/[.+^${}()|[\]\\]/g, '\\$&') // Escape regex special chars except * and ?
181→      .replace(/\*/g, '.*')  // * becomes .*
182→      .replace(/\?/g, '.');  // ? becomes .
183→
184→    try {
