  2→import type { WorkgroupResponse } from '../services/workgroupApi';
  3→import { moveWorkgroup, getRootWorkgroups, getWorkgroupChildren } from '../services/workgroupApi';
  4→
  5→/**
  6→ * Move Workgroup Modal Component
  7→ * Feature 040: Nested Workgroups (User Story 3)
  8→ *
  9→ * Modal dialog for moving a workgroup to a different parent or root level.
 10→ * Validates:
 11→ * - Cannot move to own descendant (circular reference)
 12→ * - Resulting depth must not exceed 5 levels
 13→ * - Name must be unique among new siblings
 14→ */
 15→
 16→interface MoveWorkgroupModalProps {
 17→  show: boolean;
 18→  workgroup: WorkgroupResponse | null;
 19→  onClose: () => void;
 20→  onSuccess: (movedWorkgroup: WorkgroupResponse) => void;
 21→}
 22→
 23→const MoveWorkgroupModal: React.FC<MoveWorkgroupModalProps> = ({
 24→  show,
 25→  workgroup,
 26→  onClose,
 27→  onSuccess
 28→}) => {
 29→  const [allWorkgroups, setAllWorkgroups] = useState<WorkgroupResponse[]>([]);
 30→  const [selectedParentId, setSelectedParentId] = useState<number | null>(null);
 31→  const [loading, setLoading] = useState(false);
 32→  const [loadingWorkgroups, setLoadingWorkgroups] = useState(false);
 33→  const [error, setError] = useState<string | null>(null);
 34→
 35→  useEffect(() => {
 36→    if (show) {
 37→      fetchAllWorkgroups();
 38→      setSelectedParentId(workgroup?.parentId ?? null);
 39→      setError(null);
 40→    }
 41→  }, [show, workgroup]);
 42→
 43→  const fetchAllWorkgroups = async () => {
 44→    setLoadingWorkgroups(true);
 45→    try {
 46→      const roots = await getRootWorkgroups();
 47→
 48→      // Recursively load all workgroups
 49→      const allWgs: WorkgroupResponse[] = [...roots];
 50→      for (const root of roots) {
 51→        await loadChildren(root, allWgs);
 52→      }
 53→
 54→      setAllWorkgroups(allWgs);
 55→    } catch (err) {
 56→      console.error('Failed to load workgroups:', err);
 57→      setError('Failed to load workgroups');
 58→    } finally {
 59→      setLoadingWorkgroups(false);
 60→    }
 61→  };
 62→
 63→  const loadChildren = async (parent: WorkgroupResponse, accumulator: WorkgroupResponse[]) => {
 64→    if (parent.hasChildren) {
 65→      try {
 66→        const children = await getWorkgroupChildren(parent.id);
 67→        accumulator.push(...children);
 68→
 69→        for (const child of children) {
 70→          await loadChildren(child, accumulator);
 71→        }
 72→      } catch (err) {
 73→        console.error(`Failed to load children for ${parent.name}:`, err);
 74→      }
 75→    }
 76→  };
 77→
 78→  const handleSubmit = async (e: React.FormEvent) => {
 79→    e.preventDefault();
 80→
 81→    if (!workgroup) {
 82→      setError('Workgroup is required');
 83→      return;
 84→    }
 85→
 86→    setLoading(true);
 87→    setError(null);
 88→
 89→    try {
 90→      const movedWorkgroup = await moveWorkgroup(workgroup.id, {
 91→        newParentId: selectedParentId
 92→      });
 93→
 94→      onSuccess(movedWorkgroup);
 95→      onClose();
 96→    } catch (err) {
 97→      if (err instanceof Error) {
 98→        setError(err.message);
 99→      } else {
100→        setError('Failed to move workgroup');
101→      }
102→      console.error('Failed to move workgroup:', err);
103→    } finally {
104→      setLoading(false);
105→    }
106→  };
107→
108→  const isDescendant = (potentialDescendant: WorkgroupResponse): boolean => {
109→    if (!workgroup) return false;
110→
111→    // Check if potentialDescendant is in the subtree of workgroup
112→    let current: WorkgroupResponse | undefined = potentialDescendant;
113→    const visited = new Set<number>();
114→
115→    while (current && current.parentId) {
116→      if (visited.has(current.parentId)) break; // Circular reference protection
117→      visited.add(current.parentId);
118→
119→      if (current.parentId === workgroup.id) {
120→        return true;
121→      }
122→
123→      // Find parent in allWorkgroups
124→      current = allWorkgroups.find(wg => wg.id === current!.parentId);
125→    }
126→
127→    return false;
128→  };
129→
130→  const getValidParentOptions = (): WorkgroupResponse[] => {
131→    if (!workgroup) return [];
132→
133→    return allWorkgroups.filter(wg => {
134→      // Cannot be self
135→      if (wg.id === workgroup.id) return false;
136→
137→      // Cannot be a descendant
138→      if (isDescendant(wg)) return false;
139→
140→      // Check depth limit (workgroup subtree depth + new parent depth must be <= 5)
141→      // For simplicity, we'll calculate max depth as current depth
142→      const maxSubtreeDepth = workgroup.depth; // Simplified: assume workgroup retains its current depth structure
143→      if (wg.depth + maxSubtreeDepth > 5) return false;
144→
145→      return true;
146→    });
147→  };
148→
149→  if (!show) return null;
150→
151→  const validParents = getValidParentOptions();
152→
153→  return (
154→    <>
155→      {/* Modal backdrop */}
156→      <div
157→        className="modal-backdrop fade show"
158→        onClick={onClose}
159→        style={{ zIndex: 1040 }}
160→      ></div>
161→
162→      {/* Modal dialog */}
163→      <div
164→        className="modal fade show d-block"
165→        tabIndex={-1}
166→        style={{ zIndex: 1050 }}
167→      >
168→        <div className="modal-dialog modal-dialog-centered modal-lg">
169→          <div className="modal-content">
170→            <div className="modal-header">
171→              <h5 className="modal-title">
172→                <i className="bi bi-arrows-move me-2"></i>
173→                Move Workgroup
174→              </h5>
175→              <button
176→                type="button"
177→                className="btn-close"
178→                onClick={onClose}
179→                disabled={loading}
180→              ></button>
181→            </div>
182→
183→            <form onSubmit={handleSubmit}>
184→              <div className="modal-body">
185→                {/* Workgroup info */}
186→                {workgroup && (
187→                  <div className="alert alert-info">
188→                    <strong>Moving:</strong> {workgroup.name}
189→                    <br />
190→                    <small className="text-muted">
191→                      Current location: {workgroup.ancestors.length > 0
192→                        ? workgroup.ancestors.map(a => a.name).join(' > ') + ' > ' + workgroup.name
193→                        : 'Root level'}
194→                    </small>
195→                    <br />
196→                    <small className="text-muted">
197→                      Depth: {workgroup.depth} / 5
198→                      {workgroup.childCount > 0 && (
199→                        <span className="ms-2">
200→                          (has {workgroup.childCount} {workgroup.childCount === 1 ? 'child' : 'children'})
201→                        </span>
202→                      )}
203→                    </small>
204→                  </div>
205→                )}
206→
207→                {/* Error alert */}
208→                {error && (
209→                  <div className="alert alert-danger">
210→                    <i className="bi bi-exclamation-triangle"></i> {error}
211→                  </div>
212→                )}
213→
214→                {/* Loading state */}
215→                {loadingWorkgroups && (
216→                  <div className="text-center py-3">
217→                    <div className="spinner-border text-primary" role="status">
218→                      <span className="visually-hidden">Loading workgroups...</span>
219→                    </div>
220→                  </div>
221→                )}
222→
223→                {/* Parent selection */}
224→                {!loadingWorkgroups && (
225→                  <div className="mb-3">
226→                    <label htmlFor="newParent" className="form-label">
227→                      New Parent <span className="text-danger">*</span>
228→                    </label>
229→                    <select
230→                      className="form-select"
231→                      id="newParent"
232→                      value={selectedParentId ?? ''}
233→                      onChange={(e) => setSelectedParentId(e.target.value ? Number(e.target.value) : null)}
234→                      disabled={loading}
235→                      required
236→                    >
237→                      <option value="">-- Move to Root Level --</option>
238→                      {validParents.map((parent) => (
239→                        <option key={parent.id} value={parent.id}>
240→                          {'  '.repeat(parent.depth - 1)}{parent.name} (Level {parent.depth})
241→                        </option>
242→                      ))}
243→                    </select>
244→                    <small className="text-muted">
245→                      {validParents.length === 0
246→                        ? 'No valid parent options available (would exceed depth limit or create circular reference)'
247→                        : `${validParents.length} valid parent option${validParents.length === 1 ? '' : 's'} available`}
248→                    </small>
249→                  </div>
250→                )}
251→
252→                {/* Validation hints */}
253→                <div className="border-top pt-3">
254→                  <h6 className="text-muted small mb-2">Validation Rules:</h6>
255→                  <ul className="small text-muted mb-0">
256→                    <li>Cannot move to own descendant (would create circular reference)</li>
257→                    <li>Name must be unique among new siblings</li>
258→                    <li>Resulting depth (including children) must not exceed 5 levels</li>
259→                    {(workgroup?.childCount ?? 0) > 0 && (
