  4→// Error Boundary Component
  5→class ErrorBoundary extends Component<
  6→  { children: React.ReactNode },
  7→  { hasError: boolean; error: Error | null }
  8→> {
  9→  constructor(props: { children: React.ReactNode }) {
 10→    super(props);
 11→    this.state = { hasError: false, error: null };
 12→  }
 13→
 14→  static getDerivedStateFromError(error: Error) {
 15→    return { hasError: true, error };
 16→  }
 17→
 18→  componentDidCatch(error: Error, errorInfo: React.ErrorInfo) {
 19→    console.error('ScanManagement Error:', error, errorInfo);
 20→  }
 21→
 22→  render() {
 23→    if (this.state.hasError) {
 24→      return (
 25→        <div className="container-fluid p-4">
 26→          <div className="alert alert-danger" role="alert">
 27→            <h4 className="alert-heading">Something went wrong</h4>
 28→            <p>Error: {this.state.error?.message || 'Unknown error'}</p>
 29→            <hr />
 30→            <button
 31→              className="btn btn-primary"
 32→              onClick={() => window.location.reload()}
 33→            >
 34→              Reload Page
 35→            </button>
 36→          </div>
 37→        </div>
 38→      );
 39→    }
 40→
 41→    return this.props.children;
 42→  }
 43→}
