  1→import React, { useState, useEffect } from 'react';
  2→import { authenticatedGet, authenticatedPost, authenticatedPut, authenticatedDelete } from '../utils/auth';
  3→
  4→interface Workgroup {
  5→  id: number;
  6→  name: string;
  7→  description?: string;
  8→  criticality: 'CRITICAL' | 'HIGH' | 'MEDIUM' | 'LOW' | 'NA';
  9→  userCount: number;
 10→  assetCount: number;
 11→  createdAt: string;
 12→  updatedAt: string;
 13→  parentId?: number;
 14→  parentName?: string;
 15→  depth?: number;
 16→  ancestors?: Array<{ id: number; name: string }>;
 17→}
 18→
 19→interface User {
 20→  id: number;
 21→  username: string;
 22→  email: string;
 23→}
 24→
 25→interface Asset {
 26→  id: number;
 27→  name: string;
 28→  type: string;
 29→}
 30→
 31→const WorkgroupManagement: React.FC = () => {
 32→  const [workgroups, setWorkgroups] = useState<Workgroup[]>([]);
 33→  const [users, setUsers] = useState<User[]>([]);
 34→  const [assets, setAssets] = useState<Asset[]>([]);
 35→  const [loading, setLoading] = useState(true);
 36→  const [error, setError] = useState<string | null>(null);
 37→  const [showForm, setShowForm] = useState(false);
 38→  const [editingWorkgroup, setEditingWorkgroup] = useState<Workgroup | null>(null);
 39→  const [formData, setFormData] = useState<{ name: string; description: string; criticality: 'CRITICAL' | 'HIGH' | 'MEDIUM' | 'LOW' | 'NA' }>({
 40→    name: '',
 41→    description: '',
 42→    criticality: 'MEDIUM'
 43→  });
 44→  const [showAssignUsers, setShowAssignUsers] = useState(false);
 45→  const [showAssignAssets, setShowAssignAssets] = useState(false);
 46→  const [selectedWorkgroup, setSelectedWorkgroup] = useState<Workgroup | null>(null);
 47→  const [selectedUserIds, setSelectedUserIds] = useState<number[]>([]);
 48→  const [selectedAssetIds, setSelectedAssetIds] = useState<number[]>([]);
 49→  const [assetSearchTerm, setAssetSearchTerm] = useState<string>('');
 50→
 51→  useEffect(() => {
 52→    fetchWorkgroups();
 53→    fetchUsers();
 54→    fetchAssets();
 55→  }, []);
 56→
 57→  const fetchWorkgroups = async () => {
 58→    try {
 59→      const response = await authenticatedGet('/api/workgroups');
 60→      if (response.ok) {
 61→        const data = await response.json();
 62→        setWorkgroups(data);
 63→      } else {
 64→        setError(`Failed to fetch workgroups: ${response.status}`);
 65→      }
 66→    } catch (err) {
 67→      setError(err instanceof Error ? err.message : 'An error occurred');
 68→    } finally {
 69→      setLoading(false);
 70→    }
 71→  };
 72→
 73→  const fetchUsers = async () => {
 74→    try {
 75→      const response = await authenticatedGet('/api/users');
 76→      if (response.ok) {
 77→        const data = await response.json();
 78→        setUsers(data);
 79→      }
 80→    } catch (err) {
 81→      console.error('Failed to fetch users:', err);
 82→    }
 83→  };
 84→
 85→  const fetchAssets = async () => {
 86→    try {
 87→      const response = await authenticatedGet('/api/assets');
 88→      if (response.ok) {
 89→        const data = await response.json();
 90→        setAssets(data);
 91→      }
 92→    } catch (err) {
 93→      console.error('Failed to fetch assets:', err);
 94→    }
 95→  };
 96→
 97→  const handleSubmit = async (e: React.FormEvent) => {
 98→    e.preventDefault();
 99→
100→    try {
101→      if (editingWorkgroup) {
102→        const response = await authenticatedPut(`/api/workgroups/${editingWorkgroup.id}`, formData);
103→        if (!response.ok) {
104→          const errorData = await response.json().catch(() => ({ error: 'Unknown error' }));
105→          throw new Error(errorData.error || `Failed to update workgroup: ${response.status}`);
106→        }
107→      } else {
108→        const response = await authenticatedPost('/api/workgroups', formData);
109→        if (!response.ok) {
110→          const errorData = await response.json().catch(() => ({ error: 'Unknown error' }));
111→          throw new Error(errorData.error || `Failed to create workgroup: ${response.status}`);
112→        }
113→      }
114→
115→      await fetchWorkgroups();
116→      resetForm();
117→      setError(null);
118→    } catch (err) {
119→      setError(err instanceof Error ? err.message : 'An error occurred');
120→    }
121→  };
122→
123→  const handleEdit = (workgroup: Workgroup) => {
124→    setEditingWorkgroup(workgroup);
125→    setFormData({
126→      name: workgroup.name,
127→      description: workgroup.description || '',
128→      criticality: workgroup.criticality
129→    });
130→    setShowForm(true);
131→  };
132→
133→  const handleDelete = async (id: number) => {
134→    if (!window.confirm('Are you sure you want to delete this workgroup? This will remove all user and asset assignments.')) {
135→      return;
136→    }
137→
138→    try {
139→      const response = await authenticatedDelete(`/api/workgroups/${id}`);
140→
141→      if (!response.ok) {
142→        const errorData = await response.json().catch(() => ({ error: 'Unknown error' }));
143→        throw new Error(errorData.error || `Failed to delete workgroup: ${response.status}`);
144→      }
145→
146→      await fetchWorkgroups();
147→      setError(null);
148→    } catch (err) {
149→      setError(err instanceof Error ? err.message : 'An error occurred while deleting the workgroup');
150→    }
151→  };
152→
153→  const handleAssignUsers = (workgroup: Workgroup) => {
154→    setSelectedWorkgroup(workgroup);
155→    setSelectedUserIds([]);
156→    setShowAssignUsers(true);
157→  };
158→
159→  const handleAssignAssets = (workgroup: Workgroup) => {
160→    setSelectedWorkgroup(workgroup);
161→    setSelectedAssetIds([]);
162→    setAssetSearchTerm('');
163→    setShowAssignAssets(true);
164→  };
165→
166→  /**
167→   * Filter assets based on search term with wildcard support
168→   * Supports: partial match, * wildcard, case-insensitive
169→   */
170→  const filterAssets = (searchTerm: string): Asset[] => {
171→    if (!searchTerm.trim()) {
172→      return assets;
173→    }
174→
175→    const term = searchTerm.toLowerCase().trim();
176→
177→    // Convert wildcard pattern to regex
178→    // * matches any characters, ? matches single character
179→    const regexPattern = term
180→      .replace(/[.+^${}()|[\]\\]/g, '\\$&') // Escape regex special chars except * and ?
181→      .replace(/\*/g, '.*')  // * becomes .*
182→      .replace(/\?/g, '.');  // ? becomes .
183→
184→    try {
185→      const regex = new RegExp(regexPattern);
186→      return assets.filter(asset =>
187→        regex.test(asset.name.toLowerCase()) ||
188→        regex.test(asset.type.toLowerCase())
189→      );
190→    } catch {
191→      // If regex is invalid, fall back to simple includes
192→      return assets.filter(asset =>
193→        asset.name.toLowerCase().includes(term) ||
194→        asset.type.toLowerCase().includes(term)
195→      );
196→    }
197→  };
198→
199→  const filteredAssets = filterAssets(assetSearchTerm);
200→
201→  const submitAssignUsers = async () => {
202→    if (!selectedWorkgroup || selectedUserIds.length === 0) {
203→      setError('Please select at least one user');
204→      return;
205→    }
206→
207→    try {
208→      const response = await authenticatedPost(`/api/workgroups/${selectedWorkgroup.id}/users`, {
209→        userIds: selectedUserIds
210→      });
211→
212→      if (!response.ok) {
213→        const errorData = await response.json().catch(() => ({ error: 'Unknown error' }));
214→        throw new Error(errorData.error || `Failed to assign users: ${response.status}`);
215→      }
216→
217→      await fetchWorkgroups();
218→      setShowAssignUsers(false);
219→      setSelectedWorkgroup(null);
220→      setSelectedUserIds([]);
221→      setError(null);
222→    } catch (err) {
223→      setError(err instanceof Error ? err.message : 'An error occurred');
224→    }
225→  };
226→
227→  const submitAssignAssets = async () => {
228→    if (!selectedWorkgroup || selectedAssetIds.length === 0) {
229→      setError('Please select at least one asset');
230→      return;
231→    }
232→
233→    try {
234→      const response = await authenticatedPost(`/api/workgroups/${selectedWorkgroup.id}/assets`, {
235→        assetIds: selectedAssetIds
236→      });
237→
238→      if (!response.ok) {
239→        const errorData = await response.json().catch(() => ({ error: 'Unknown error' }));
240→        throw new Error(errorData.error || `Failed to assign assets: ${response.status}`);
241→      }
242→
243→      await fetchWorkgroups();
244→      setShowAssignAssets(false);
245→      setSelectedWorkgroup(null);
246→      setSelectedAssetIds([]);
247→      setError(null);
248→    } catch (err) {
249→      setError(err instanceof Error ? err.message : 'An error occurred');
250→    }
251→  };
252→
253→  const toggleUserSelection = (userId: number) => {
254→    setSelectedUserIds(prev =>
255→      prev.includes(userId) ? prev.filter(id => id !== userId) : [...prev, userId]
256→    );
257→  };
258→
259→  const toggleAssetSelection = (assetId: number) => {
260→    setSelectedAssetIds(prev =>
261→      prev.includes(assetId) ? prev.filter(id => id !== assetId) : [...prev, assetId]
262→    );
263→  };
264→
265→  const resetForm = () => {
266→    setFormData({ name: '', description: '', criticality: 'MEDIUM' });
267→    setEditingWorkgroup(null);
268→    setShowForm(false);
269→  };
270→
271→  if (loading) {
272→    return <div className="text-center p-4">Loading workgroups...</div>;
273→  }
274→
275→  return (
276→    <div className="container mt-4">
277→      <div className="d-flex justify-content-between align-items-center mb-4">
