  1→/**
  2→ * MyExceptionRequests Component
  3→ *
  4→ * Dashboard page for viewing and managing user's own exception requests
  5→ *
  6→ * Features:
  7→ * - Summary statistics cards (Total, Approved, Pending, Rejected)
  8→ * - Status filter dropdown
  9→ * - Paginated table with sortable columns
 10→ * - View details modal
 11→ * - Cancel pending requests
 12→ * - Empty state handling
 13→ *
 14→ * Feature: 031-vuln-exception-approval
 15→ * User Story 1: Regular User Requests Exception (P1)
 16→ * Reference: spec.md FR-010 to FR-017
 17→ */
 18→
 19→import React, { useState, useEffect } from 'react';
 20→import {
 21→    getMyRequests,
 22→    getMySummary,
 23→    cancelRequest,
 24→    deleteRequest,
 25→    type VulnerabilityExceptionRequestDto,
 26→    type ExceptionRequestSummaryDto,
 27→    type ExceptionRequestStatus,
 28→    type PagedResponse
 29→} from '../services/exceptionRequestService';
 30→import ExceptionStatusBadge from './ExceptionStatusBadge';
 31→import ExceptionRequestDetailModal from './ExceptionRequestDetailModal';
 32→
 33→const MyExceptionRequests: React.FC = () => {
 34→    // Data states
 35→    const [requests, setRequests] = useState<PagedResponse<VulnerabilityExceptionRequestDto> | null>(null);
 36→    const [summary, setSummary] = useState<ExceptionRequestSummaryDto | null>(null);
 37→    const [loading, setLoading] = useState(true);
 38→    const [error, setError] = useState<string | null>(null);
 39→    const [successMessage, setSuccessMessage] = useState<string | null>(null);
 40→
 41→    // Filter and pagination states
 42→    const [statusFilter, setStatusFilter] = useState<ExceptionRequestStatus | undefined>(undefined);
 43→    const [currentPage, setCurrentPage] = useState(0);
 44→    const [pageSize, setPageSize] = useState(20);
 45→
 46→    // Modal states
 47→    const [showDetailModal, setShowDetailModal] = useState(false);
 48→    const [selectedRequestId, setSelectedRequestId] = useState<number | null>(null);
 49→
 50→    // Cancellation and deletion state
 51→    const [cancellingId, setCancellingId] = useState<number | null>(null);
 52→    const [deletingId, setDeletingId] = useState<number | null>(null);
 53→
 54→    useEffect(() => {
 55→        fetchData();
 56→    }, [statusFilter, currentPage, pageSize]);
 57→
 58→    const fetchData = async () => {
 59→        try {
 60→            setLoading(true);
 61→            setError(null);
 62→
 63→            // Fetch summary and requests in parallel
 64→            const [summaryData, requestsData] = await Promise.all([
 65→                getMySummary(),
 66→                getMyRequests(statusFilter, currentPage, pageSize)
 67→            ]);
 68→
 69→            setSummary(summaryData);
 70→            setRequests(requestsData);
 71→        } catch (err) {
 72→            const errorMessage = err instanceof Error ? err.message : 'Failed to load exception requests';
 73→            setError(errorMessage);
 74→        } finally {
 75→            setLoading(false);
 76→        }
 77→    };
 78→
 79→    const handleStatusFilterChange = (status: string) => {
 80→        setStatusFilter(status === '' ? undefined : status as ExceptionRequestStatus);
 81→        setCurrentPage(0); // Reset to first page when filter changes
 82→    };
 83→
 84→    const handlePageSizeChange = (size: number) => {
 85→        setPageSize(size);
 86→        setCurrentPage(0); // Reset to first page when page size changes
 87→    };
 88→
 89→    const handleViewDetails = (requestId: number) => {
 90→        setSelectedRequestId(requestId);
 91→        setShowDetailModal(true);
 92→    };
 93→
 94→    const handleCloseDetailModal = () => {
 95→        setShowDetailModal(false);
 96→        setSelectedRequestId(null);
 97→    };
 98→
 99→    const handleCancelRequest = async (requestId: number) => {
100→        if (!confirm('Are you sure you want to cancel this exception request?')) {
101→            return;
102→        }
103→
104→        try {
105→            setCancellingId(requestId);
106→            await cancelRequest(requestId);
107→
108→            setSuccessMessage('Exception request cancelled successfully.');
109→
110→            // Auto-dismiss success message after 5 seconds
111→            setTimeout(() => {
112→                setSuccessMessage(null);
113→            }, 5000);
114→
115→            // Refresh data
116→            fetchData();
117→        } catch (err) {
118→            const errorMessage = err instanceof Error ? err.message : 'Failed to cancel request';
119→            setError(errorMessage);
120→        } finally {
121→            setCancellingId(null);
122→        }
123→    };
124→
125→    const handleDeleteRequest = async (requestId: number) => {
126→        if (!confirm('Are you sure you want to permanently delete this exception request? This will also remove any associated exception.')) {
127→            return;
128→        }
129→
130→        try {
131→            setDeletingId(requestId);
132→            await deleteRequest(requestId);
133→
134→            setSuccessMessage('Exception request deleted successfully.');
135→
136→            setTimeout(() => {
137→                setSuccessMessage(null);
138→            }, 5000);
139→
140→            fetchData();
